     2	
     3	#include "native_context_extraction.hpp"
     4	#include "function_call_extractor.hpp"
     5	#include <tree_sitter/api.h>
     6	
     7	namespace duckdb {
     8	
     9	//==============================================================================
    10	// Rust-Specific Native Context Extractors
    11	//==============================================================================
    12	
    13	// Forward declaration for RustAdapter
    14	class RustAdapter;
    15	
    16	// Base template for Rust extractors - default returns empty context
    17	template <NativeExtractionStrategy Strategy>
    18	struct RustNativeExtractor {
    19		static NativeContext Extract(TSNode node, const string &content) {
    20			return NativeContext(); // Default: no extraction
    21		}
    22	};
    23	
    24	// Specialization for FUNCTION_WITH_PARAMS (Rust functions)
    25	template <>
    26	struct RustNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS> {
    27		static NativeContext Extract(TSNode node, const string &content) {
    28			NativeContext context;
    29	
    30			try {
    31				// Extract return type (Rust functions use -> Type syntax)
    32				context.signature_type = ExtractRustReturnType(node, content);
    33	
    34				// If no explicit return type, default to unit type ()
    35				if (context.signature_type.empty()) {
    36					context.signature_type = "()";
    37				}
    38	
    39				// Extract function parameters with Rust type annotations
    40				context.parameters = ExtractRustParameters(node, content);
    41	
    42				// Extract function modifiers and attributes
    43				auto modifiers = ExtractRustModifiers(node, content);
    44				context.modifiers = modifiers;
    45	
    46			} catch (...) {
    47				context.signature_type = "()"; // Default to unit type
    48				context.parameters.clear();
    49				context.modifiers.clear();
    50			}
    51	
    52			return context;
    53		}
    54	
    55	private:
    56		static string ExtractRustReturnType(TSNode node, const string &content) {
    57			// Look for -> return_type pattern
    58			uint32_t child_count = ts_node_child_count(node);
    59			for (uint32_t i = 0; i < child_count; i++) {
    60				TSNode child = ts_node_child(node, i);
    61				const char *child_type = ts_node_type(child);
    62	
    63				if (strcmp(child_type, "->") == 0 && i + 1 < child_count) {
    64					// Next child should be the return type
    65					TSNode type_node = ts_node_child(node, i + 1);
    66					uint32_t start = ts_node_start_byte(type_node);
    67					uint32_t end = ts_node_end_byte(type_node);
    68					if (start < content.length() && end <= content.length()) {
    69						return content.substr(start, end - start);
    70					}
    71				}
    72			}
    73			return ""; // No return type annotation (defaults to unit type ())
    74		}
    75	
    76		static vector<ParameterInfo> ExtractRustParameters(TSNode node, const string &content) {
    77			vector<ParameterInfo> params;
    78	
    79			// Find parameters node
    80			uint32_t child_count = ts_node_child_count(node);
    81			for (uint32_t i = 0; i < child_count; i++) {
    82				TSNode child = ts_node_child(node, i);
    83				const char *child_type = ts_node_type(child);
    84	
    85				if (strcmp(child_type, "parameters") == 0) {
    86					params = ExtractRustParametersDirect(child, content);
    87					break;
    88				}
    89			}
    90	
    91			return params;
    92		}
    93	
    94		static vector<ParameterInfo> ExtractRustParametersDirect(TSNode params_node, const string &content) {
    95			vector<ParameterInfo> parameters;
    96	
    97			uint32_t child_count = ts_node_child_count(params_node);
    98	
    99			for (uint32_t i = 0; i < child_count; i++) {
   100				TSNode child = ts_node_child(params_node, i);
   101				const char *child_type = ts_node_type(child);
   102	
   103				ParameterInfo param;
   104				bool is_valid_param = false;
   105	
   106				if (strcmp(child_type, "parameter") == 0) {
   107					// Standard parameter: param: Type
   108					param = ExtractRustParameter(child, content);
   109					is_valid_param = !param.name.empty();
   110				} else if (strcmp(child_type, "self_parameter") == 0) {
   111					// Self parameter: self, &self, &mut self
   112					param = ExtractRustSelfParameter(child, content);
   113					is_valid_param = !param.name.empty();
   114				}
   115	
   116				if (is_valid_param) {
   117					parameters.push_back(param);
   118				}
   119			}
   120	
   121			return parameters;
   122		}
   123	
   124		static ParameterInfo ExtractRustParameter(TSNode node, const string &content) {
   125			ParameterInfo param;
   126			uint32_t child_count = ts_node_child_count(node);
   127	
   128			for (uint32_t i = 0; i < child_count; i++) {
   129				TSNode child = ts_node_child(node, i);
   130				const char *child_type = ts_node_type(child);
   131	
   132				if (strcmp(child_type, "identifier") == 0) {
   133					// Parameter name
   134					uint32_t start = ts_node_start_byte(child);
   135					uint32_t end = ts_node_end_byte(child);
   136					if (start < content.length() && end <= content.length()) {
