 25	template <>
 26	struct RustNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS> {
 27		static NativeContext Extract(TSNode node, const string &content) {
 28			NativeContext context;
 29	
 30			try {
 31				// Extract return type (Rust functions use -> Type syntax)
 32				context.signature_type = ExtractRustReturnType(node, content);
 33	
 34				// If no explicit return type, default to unit type ()
 35				if (context.signature_type.empty()) {
 36					context.signature_type = "()";
 37				}
 38	
 39				// Extract function parameters with Rust type annotations
