 55	private:
 56		static string ExtractRustReturnType(TSNode node, const string &content) {
 57			// Look for -> return_type pattern
 58			uint32_t child_count = ts_node_child_count(node);
 59			for (uint32_t i = 0; i < child_count; i++) {
 60				TSNode child = ts_node_child(node, i);
 61				const char *child_type = ts_node_type(child);
 62	
 63				if (strcmp(child_type, "->") == 0 && i + 1 < child_count) {
 64					// Next child should be the return type
 65					TSNode type_node = ts_node_child(node, i + 1);
 66					uint32_t start = ts_node_start_byte(type_node);
 67					uint32_t end = ts_node_end_byte(type_node);
