 76		static vector<ParameterInfo> ExtractRustParameters(TSNode node, const string &content) {
 77			vector<ParameterInfo> params;
 78	
 79			// Find parameters node
 80			uint32_t child_count = ts_node_child_count(node);
 81			for (uint32_t i = 0; i < child_count; i++) {
 82				TSNode child = ts_node_child(node, i);
 83				const char *child_type = ts_node_type(child);
