140				           strcmp(child_type, "generic_type") == 0 || strcmp(child_type, "reference_type") == 0 ||
141				           strcmp(child_type, "pointer_type") == 0) {
142					// Parameter type
143					uint32_t start = ts_node_start_byte(child);
144					uint32_t end = ts_node_end_byte(child);
145					if (start < content.length() && end <= content.length()) {
146						param.type = content.substr(start, end - start);
147					}
